#
# Name
#
#	t_killit.sh
#
# Description
#
#	Shell script to kill processes generated by t_reqpk_read.sh
#	It reads a file called t_kill_file to extract the pids created
#	in testing and then applies a kill to each of them whether they
#	still exit or not.
#

#	Don't fail if a pid doesn't exist
set +e

#	Read the file and input the pids
while [ 1 ]
do

    read pid
    echo $pid
    if [ $pid ]
    then
	kill -TERM $pid
    else
	break
    fi

done < t_kill_file

rm t_kill_file

